// =======================================
func (q *Queries) GetProducts(ctx context.Context) ([]Product, error) {
	rows, err := q.db.Query(ctx, getProducts)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []Product
	for rows.Next() {
		var i Product
		if err := rows.Scan(
			&i.ID,
			&i.CategoryID,
			&i.Name,
			&i.Description,
			&i.IsActive,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const getProductsByCategory = `-- name: GetProductsByCategory :many
SELECT p.id, p.name, p.description, (
        SELECT image_url
        FROM product_images pi
        WHERE
            pi.product_id = p.id
            AND pi.is_primary = true
        LIMIT 1
    ) AS image, (
        SELECT MIN(price)
        FROM product_variants pv
        WHERE
            pv.product_id = p.id
    ) AS price_from
FROM products p
WHERE
    p.category_id = $1
    AND p.is_active = true
ORDER BY p.created_at DESC
LIMIT $2
OFFSET
    $3
`

type GetProductsByCategoryParams struct {
	CategoryID pgtype.Int4
	Limit      int32
	Offset     int32
}

type GetProductsByCategoryRow struct {
	ID          int32
	Name        string
	Description pgtype.Text
	Image       string
	PriceFrom   interface{}
}

func (q *Queries) GetProductsByCategory(ctx context.Context, arg GetProductsByCategoryParams) ([]GetProductsByCategoryRow, error) {
	rows, err := q.db.Query(ctx, getProductsByCategory, arg.CategoryID, arg.Limit, arg.Offset)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []GetProductsByCategoryRow
	for rows.Next() {
		var i GetProductsByCategoryRow
		if err := rows.Scan(
			&i.ID,
			&i.Name,
			&i.Description,
			&i.Image,
			&i.PriceFrom,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

