const reserveStock = `-- name: ReserveStock :one
UPDATE inventory
SET
    reserved_stock = reserved_stock + $2
WHERE
    variant_id = $1
    AND stock - reserved_stock >= $2
RETURNING
    id, variant_id, stock, reserved_stock, updated_at
`

